def debug_decorator(func):
    def wrapper(*args, **kwargs):
        print(f"Aufruf von {func.__name__} mit args: {args}")
        result = func(*args, **kwargs)
        print(f"{func.__name__} hat {result} zurückgegeben")
        return result
    return wrapper

@debug_decorator
def multiply(x, y):
    return x * y

print(multiply(3, 4))

